var timingMarkdownLink = regexp.MustCompile(`\[[^\]]*\]\(\s*<?([^)\s>]+)>?`)

func mostLinkedRepositoryFile(root string) (string, int, error) {
	counts := make(map[string]int)

	err := filepath.WalkDir(root, func(path string, entry fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if entry.Type()&os.ModeSymlink != 0 {
			return nil
		}
		if entry.IsDir() {
			if path != root && shouldSkipTimingDirectory(entry.Name()) {
				return filepath.SkipDir
			}
			return nil
		}

		extension := strings.ToLower(filepath.Ext(path))
		if extension != ".md" && extension != ".markdown" {
			return nil
		}

		data, err := os.ReadFile(path)
		if err != nil {
			return err
		}

		for _, match := range timingMarkdownLink.FindAllStringSubmatch(string(data), -1) {
			target := strings.TrimSpace(match[1])
			target = strings.Trim(target, "<>")
			if target == "" || strings.HasPrefix(target, "#") || strings.HasPrefix(target, "//") {
				continue
			}

			parsed, err := url.Parse(target)
			if err != nil || parsed.IsAbs() || parsed.Path == "" {
				continue
			}

			targetPath := filepath.FromSlash(parsed.Path)
			if filepath.IsAbs(targetPath) {
				continue
			}

			candidate := filepath.Clean(filepath.Join(filepath.Dir(path), targetPath))
			relative, err := filepath.Rel(root, candidate)
			if err != nil || relative == ".." || strings.HasPrefix(relative, ".."+string(filepath.Separator)) {
				continue
			}

			info, err := os.Lstat(candidate)
			if err != nil || info.IsDir() || info.Mode()&os.ModeSymlink != 0 {
				continue
			}

			counts[candidate]++
		}

		return nil
	})
	if err != nil {
		return "", 0, err
	}

	candidates := make([]string, 0, len(counts))
	for candidate := range counts {
		candidates = append(candidates, candidate)
	}
	sort.Strings(candidates)

	var best string
	bestCount := 0
	for _, candidate := range candidates {
		if counts[candidate] > bestCount {
			best = candidate
			bestCount = counts[candidate]
		}
	}

	return best, bestCount, nil
}

func shouldSkipTimingDirectory(name string) bool {
	switch name {
	case ".ddocs", ".git", ".hg", ".svn", "node_modules":
		return true
	default:
		return false
	}
}

func timingRenamePath(path string) string {
	extension := filepath.Ext(path)
	if extension == "" {
		return path + "-timing-renamed"
	}

	base := strings.TrimSuffix(path, extension)
	return base + "-timing-renamed" + extension
}
