		t.Fatal(err)
	}
	assertReconcileTimingInvariants(t, baselineReconcileTimings)

	targetRecord, inbound, ok := mostLinkedFixtureFile(root, baseline)
	if !ok {
		t.Skip("fixture contains no uniquely identifiable repository file with inbound links")
	}

	target := recordAbsolute(root, targetRecord)
	renamed := target + ".timing-renamed"
	if _, err := os.Lstat(renamed); err == nil {
		t.Fatalf("rename target already exists: %q", renamed)
	} else if !os.IsNotExist(err) {
		t.Fatal(err)
	}

	baselineApplied, baselineApplyTimings, err := applyAndSaveWithTimings(&baseline)
	if err != nil {
		t.Fatal(err)
	}
	assertApplyTimingInvariants(t, baselineApplyTimings)

	if err := os.Rename(target, renamed); err != nil {
		t.Fatal(err)
	}

	plan, reconcileTimings, err := reconcileWithTimings(root)
	if err != nil {
		t.Fatal(err)
	}
	assertReconcileTimingInvariants(t, reconcileTimings)

	if len(plan.Rewrites) == 0 {
		t.Fatalf("renaming %q with %d inbound links produced no rewrites", target, inbound)
	}

	applied, applyTimings, err := applyAndSaveWithTimings(&plan)
	if err != nil {
		t.Fatal(err)
	}
	assertApplyTimingInvariants(t, applyTimings)

	if applied != len(plan.Rewrites) {
		t.Fatalf("applied %d rewrites; plan contains %d", applied, len(plan.Rewrites))
	}

	followup, followupReconcileTimings, err := reconcileWithTimings(root)
	if err != nil {
		t.Fatal(err)
	}
	assertReconcileTimingInvariants(t, followupReconcileTimings)

	if len(followup.Rewrites) != 0 {
		t.Fatalf("idempotent follow-up produced %d rewrites; want zero", len(followup.Rewrites))
	}

	followupApplied, followupApplyTimings, err := applyAndSaveWithTimings(&followup)
	if err != nil {
		t.Fatal(err)
	}
	assertApplyTimingInvariants(t, followupApplyTimings)

	if followupApplied != 0 {
		t.Fatalf("idempotent follow-up applied %d rewrites; want zero", followupApplied)
	}

	t.Logf("baseline reconcile: %s", baselineReconcileTimings)
	t.Logf("baseline apply:     %s; rewrites=%d", baselineApplyTimings, baselineApplied)
	t.Logf("rename target:      %s; inbound-links=%d", target, inbound)
	t.Logf("rename reconcile:   %s; rewrites=%d updates=%d", reconcileTimings, len(plan.Rewrites), len(plan.Updates))
	t.Logf("rename apply:       %s; rewrites=%d", applyTimings, applied)
	t.Logf("follow-up reconcile: %s; rewrites=%d updates=%d", followupReconcileTimings, len(followup.Rewrites), len(followup.Updates))
	t.Logf("follow-up apply:     %s; rewrites=%d", followupApplyTimings, followupApplied)
}

func mostLinkedFixtureFile(root string, plan Plan) (FileRecord, int, bool) {
	records := make([]FileRecord, 0, len(plan.Files.Files))
	fingerprintCounts := make(map[string]int)

	for _, record := range plan.Files.Files {
		if !record.Present ||
			record.Scope != "repository" ||
			record.Kind != "file" ||
			record.Fingerprint == "" {
			continue
		}

		records = append(records, record)
		fingerprintCounts[record.Fingerprint]++
	}

	records = filteredUniqueFixtureRecords(records, fingerprintCounts)
	sort.Slice(records, func(i, j int) bool {
		if records[i].ID != records[j].ID {
			return records[i].ID < records[j].ID
		}
		return records[i].Path < records[j].Path
	})

	inbound := make(map[string]int)
	candidates := make(map[string]struct{}, len(records))
	for _, record := range records {
		candidates[record.ID] = struct{}{}
	}

	for _, link := range plan.Links.Links {
		if link.TargetFileID == "" {
			continue
		}
		if link.Status != "valid" && link.Status != "moved" {
			continue
		}
		if _, ok := candidates[link.TargetFileID]; ok {
			inbound[link.TargetFileID]++
		}
	}

	var selected FileRecord
	selectedCount := 0
	found := false
	for _, record := range records {
		count := inbound[record.ID]
		if !found || count > selectedCount {
			selected = record
			selectedCount = count
			found = true
		}
	}

	if !found || selectedCount == 0 {
		return FileRecord{}, 0, false
	}
	return selected, selectedCount, true
}

func filteredUniqueFixtureRecords(records []FileRecord, counts map[string]int) []FileRecord {
	unique := make([]FileRecord, 0, len(records))
	for _, record := range records {
		if counts[record.Fingerprint] == 1 {
			unique = append(unique, record)
		}
	}
	return unique
}

type copiedFixtureDirectory struct {
	path string
	mode os.FileMode
	time fs.FileInfo
}

func copyExternalFixture(t *testing.T, source, destination string) {
	t.Helper()

	directories := make([]copiedFixtureDirectory, 0)

	err := filepath.WalkDir(source, func(path string, entry fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if entry.Type()&os.ModeSymlink != 0 {
			return nil
		}

		relative, err := filepath.Rel(source, path)
		if err != nil {
			return err
		}

		target := destination
		if relative != "." {
			target = filepath.Join(destination, relative)
		}

		info, err := entry.Info()
		if err != nil {
			return err
		}

		if entry.IsDir() {
			if err := os.MkdirAll(target, info.Mode().Perm()); err != nil {
				return err
			}
			if err := os.Chmod(target, info.Mode().Perm()); err != nil {
				return err
			}
			directories = append(directories, copiedFixtureDirectory{
				path: target,
				mode: info.Mode(),
				time: info,
			})
			return nil
		}

		if !info.Mode().IsRegular() {
			return nil
		}

		data, err := os.ReadFile(path)
		if err != nil {
			return err
		}
		if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
			return err
		}
		if err := os.WriteFile(target, data, info.Mode().Perm()); err != nil {
			return err
		}
		if err := os.Chmod(target, info.Mode().Perm()); err != nil {
			return err
		}
		return os.Chtimes(target, info.ModTime(), info.ModTime())
	})
	if err != nil {
		t.Fatal(err)
	}

	for index := len(directories) - 1; index >= 0; index-- {
		directory := directories[index]
		if err := os.Chmod(directory.path, directory.mode.Perm()); err != nil {
			t.Fatal(err)
		}
		if err := os.Chtimes(directory.path, directory.time.ModTime(), directory.time.ModTime()); err != nil {
			t.Fatal(err)
		}
	}
}
